parameters.jsCode:
const items = $items("seatalk_bot");

const result = items.map(item => {
  const email = item.json.body?.event?.email || "";
  const employee_code = item.json.body?.event?.employee_code || "";
  const content = item.json.body?.event?.message?.text?.content || "";

  let name = "";
  let code = "";

  // Kiểm tra và xử lý cả "/reg" và "reg"
  if (content.startsWith("/reg") || content.startsWith("reg")) {
    // Loại bỏ "/reg" hoặc "reg" và trim khoảng trắng
    const parts = content.replace(/^\/?reg\s*/, "").trim().split("/");

    name = parts[0]?.trim() || "";
    code = parts[1]?.trim() || "";
  }

  // Name: Unicode (tiếng Việt) + số + khoảng trắng
  const nameRegex = /^[\p{L}0-9\s]+$/u;

  // Code: CP + đúng 2 hoặc 4 số
  const codeRegex = /^CP(\d{2}|\d{4})$/;

  if (!nameRegex.test(name)) {
    name = "sai";
  }

  if (!codeRegex.test(code)) {
    code = "sai";
  }

  return {
    json: {
      email,
      name,
      code,
      employee_code
    }
  };
});

return result;

const item = $input.first().json;
const email = item.body?.event?.email || "";
const content = item.body?.event?.message?.text?.content || "";

function convertToNoAccents(str) {
  const accents = [
    { base: 'a', letters: /[àáạảãâầấậẩẫăằắặẳẵ]/g },
    { base: 'e', letters: /[èéẹẻẽêềếệểễ]/g },
    { base: 'i', letters: /[ìíịỉĩ]/g },
    { base: 'o', letters: /[òóọỏõôồốộổỗơờớợởỡ]/g },
    { base: 'u', letters: /[ùúụủũûừứựửữ]/g },
    { base: 'y', letters: /[ỳýỵỷỹ]/g },
    { base: 'd', letters: /[đ]/g },
  ];
  accents.forEach(acc => {
    str = str.replace(acc.letters, acc.base);
  });
  return str;
}

let amount = "";
let order_code = "";

if (content.startsWith("/qr") || content.startsWith("qr")) {
  const parts = content.replace(/^\/?qr\s*/, "").trim();

  // Tìm vị trí dấu "/", space, "." hoặc "," đầu tiên
  const separatorMatch = parts.match(/[\/\s.,]/);
  const separatorIndex = separatorMatch ? parts.indexOf(separatorMatch[0]) : -1;

  if (separatorIndex !== -1) {
    amount = parts.slice(0, separatorIndex).trim();
    order_code = parts.slice(separatorIndex + 1).trim();
    order_code = convertToNoAccents(order_code);
    order_code = order_code.replace(/[^a-zA-Z0-9\s]/g, ' ');
  }
}

return [{ json: { email, amount, order_code } }];

